const Achievements = ()=> {
    return(
            <AwesomeSlider animation="cubeAnimation">
                <div data-src="/path/to/image-0.png"/>
                <div data-src="/path/to/image-1.png"/>
                <div data-src="/path/to/image-2.jpg"/>
            </AwesomeSlider>
